  1	import * as React from 'react';
  2	import { FileSystemKind } from '@odf/core/types/scale';
  3	import { getName, getNamespace } from '@odf/shared';
  4	import { FileSystemModel } from '@odf/shared/models/scale';
  5	import { GreenCheckCircleIcon } from '@odf/shared/status/icons';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import { referenceForModel } from '@odf/shared/utils';
  8	import {
  9	  useK8sWatchResource,
 10	  RedExclamationCircleIcon,
 11	  YellowExclamationTriangleIcon,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import { Link, useLocation } from 'react-router-dom-v5-compat';
 14	import {
 15	  Card,
 16	  CardBody,
 17	  CardHeader,
 18	  CardTitle,
 19	  pluralize,
 20	  TextContent,
 21	  TextVariants,
 22	  Text,
 23	  EmptyState,
 24	  EmptyStateIcon,
 25	  EmptyStateVariant,
 26	  Title,
 27	} from '@patternfly/react-core';
 28	import { CubesIcon } from '@patternfly/react-icons';
 29	import { Thead, Tr, Th, Tbody, Table, Td } from '@patternfly/react-table';
 30	import { filterScaleFileSystems } from '../ibm-common/utils';
 31	
 32	const resource = {
 33	  kind: referenceForModel(FileSystemModel),
 34	  isList: true,
 35	};
 36	
 37	const isConnected = (fileSystem: FileSystemKind) => {
 38	  return fileSystem.status?.conditions?.some(
 39	    (condition) => condition.type === 'Success' && condition.status === 'True'
 40	  );
 41	};
 42	
 43	const FileSystemStatusIcon: React.FC<{
 44	  fileSystems: FileSystemKind[];
 45	  loading: boolean;
 46	  loadError: boolean;
 47	}> = ({ fileSystems, loading, loadError }) => {
 48	  if (fileSystems?.length === 0 || loading || loadError) {
 49	    return null;
 50	  }
 51	  const areAllFileSystemsConnected = fileSystems.every(
 52	    (fileSystem) =>
 53	      fileSystem.status?.conditions?.find(
 54	        (condition) => condition.type === 'Success'
 55	      )?.status === 'True'
 56	  );
 57	  const isAnyFileSystemConnected = fileSystems.some(
 58	    (fileSystem) =>
 59	      fileSystem.status?.conditions?.find(
 60	        (condition) => condition.type === 'Success'
 61	      )?.status === 'True'
 62	  );
 63	  if (areAllFileSystemsConnected) {
 64	    return <GreenCheckCircleIcon />;
 65	  }
 66	  if (isAnyFileSystemConnected) {
 67	    return <YellowExclamationTriangleIcon />;
 68	  }
 69	  return <RedExclamationCircleIcon />;
 70	};
 71	
 72	const FileSystemsTable: React.FC = () => {
 73	  const { t } = useCustomTranslation();
 74	  const [fileSystems, fileSystemsLoaded, fileSystemsLoadError] =
 75	    useK8sWatchResource<FileSystemKind[]>(resource);
 76	  const filteredFileSystems = filterScaleFileSystems(fileSystems);
 77	  const connectedFileSystems = filteredFileSystems?.filter((fileSystem) =>
 78	    isConnected(fileSystem)
 79	  );
 80	  const location = useLocation();
 81	  // odf/external-systems/scale.spectrum.ibm.com~v1beta1~remotecluster/:systemName
 82	  const externalSystemName = location.pathname.split('/')[3];
 83	  return (
 84	    <div>
 85	      <TextContent className="pf-v6-u-my-xl">
 86	        <Text component={TextVariants.h2}>
 87	          <span className="pf-v6-u-mr-sm">
 88	            <FileSystemStatusIcon
 89	              fileSystems={filteredFileSystems}
 90	              loading={!fileSystemsLoaded}
 91	              loadError={fileSystemsLoadError}
 92	            />
 93	          </span>
 94	          {t('{{ filesystems }} connected', {
 95	            filesystems: pluralize(
 96	              connectedFileSystems?.length,
 97	              t('filesystem')
 98	            ),
 99	          })}
100	        </Text>
101	      </TextContent>
102	      {filteredFileSystems?.length > 0 ? (
103	        <Table aria-label={t('File systems table')} variant="compact">
104	          <Thead>
105	            <Tr>
106	              <Th>{t('Name')}</Th>
107	              <Th>{t('Connection status')}</Th>
108	            </Tr>
109	          </Thead>
110	          <Tbody>
111	            {filteredFileSystems?.map((fileSystem: FileSystemKind) => (
112	              <Tr key={fileSystem.metadata.uid}>
113	                <Td>
114	                  <Link
115	                    to={`/odf/external-systems/scale.spectrum.ibm.com~v1beta1~cluster/${externalSystemName}/filesystems/ns/${getNamespace(fileSystem)}/${getName(fileSystem)}`}
116	                  >
117	                    {getName(fileSystem)}
118	                  </Link>
119	                </Td>
120	                <Td>
121	                  {isConnected(fileSystem) ? t('Connected') : t('Disconnected')}
122	                </Td>
123	              </Tr>
124	            ))}
125	          </Tbody>
126	        </Table>
127	      ) : (
128	        <EmptyState variant={EmptyStateVariant.sm}>
129	          <EmptyStateIcon icon={CubesIcon} />
130	          <Title headingLevel="h5" size="lg">
131	            {t('No file systems found')}
132	          </Title>
133	        </EmptyState>
134	      )}
135	    </div>
136	  );
137	};
138	
139	const FileSystemsCard: React.FC<{}> = () => {
140	  const { t } = useCustomTranslation();
141	
142	  return (
143	    <Card>
144	      <CardHeader>
145	        <CardTitle>{t('File systems')}</CardTitle>
146	      </CardHeader>
147	      <CardBody>
148	        <FileSystemsTable />
149	      </CardBody>
150	    </Card>
151	  );
152	};
153	
154	export default FileSystemsCard;

